import{_ as a,o as t,c as r,ak as o}from"./chunks/framework.d_5_XLDx.js";const m=JSON.parse('{"title":"使用cloudflare进行URL重定向","description":"","frontmatter":{"title":"使用cloudflare进行URL重定向","createTime":"2024/08/31 21:12:45","permalink":"/article/jqtuqouj/","tags":["cloudflare","URL重定向","wordpress","github pages","博客"]},"headers":[],"relativePath":"blog/ermao/文档/使用cloudflare进行URL重定向.md","filePath":"blog/ermao/文档/使用cloudflare进行URL重定向.md","lastUpdated":1769776243000}'),l={name:"blog/ermao/文档/使用cloudflare进行URL重定向.md"};function s(p,e,i,n,c,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<p>之前我的博客一直使用 wordpress，但是由于 wordpress 太过笨重、维护难度大、国内访问速度慢、还需要花钱租用后端服务器。所以我决定迁移到 github pages 重搞一个博客。</p><p>但是之前放在公网上的文章链接都是 wordpress 的，我又舍不得放弃这部分流量，所以用 cloudflare 进行URL重定向，原来的访问直接 301 跳转到了现在的地址。</p><p>需要迁移网站的同学不如试试这个方法，无痛迁移，还能保留原有的流量。</p><h2 id="_1-在-cloudflare-解析你的域名" tabindex="-1">1. 在 cloudflare 解析你的域名 <a class="header-anchor" href="#_1-在-cloudflare-解析你的域名" aria-label="Permalink to &quot;1. 在 cloudflare 解析你的域名&quot;">​</a></h2><p><img src="https://image.ermao.net/images/article/jqtuqouj/image.png" alt="alt text"></p><p>我要把 <a href="./blog.ermao.net.html">blog.ermao.net</a> 跟 <a href="./ermao.net.html">ermao.net</a> 的所有请求都重定向到 <a href="./www.ermao.net.html">www.ermao.net</a>。</p><p>所以要将 <a href="./blog.ermao.net.html">blog.ermao.net</a> 跟 <a href="./ermao.net.html">ermao.net</a> 都在cloudflare上解析。这个 ip 可以随便填，但是代理状态必须是已代理。</p><p>目标地址 <a href="./www.ermao.net.html">www.ermao.net</a> 则正常使用<code>CNAME</code>解析到 github pages 即可。</p><h2 id="_2-在-cloudflare-进行url重定向" tabindex="-1">2. 在 cloudflare 进行URL重定向 <a class="header-anchor" href="#_2-在-cloudflare-进行url重定向" aria-label="Permalink to &quot;2. 在 cloudflare 进行URL重定向&quot;">​</a></h2><p><img src="https://image.ermao.net/images/article/jqtuqouj/image-1.png" alt="alt text"></p><p>依次点击<code>规则</code> -&gt; <code>重定向规则</code> -&gt; <code>创建规则</code>。</p><p><img src="https://image.ermao.net/images/article/jqtuqouj/image-2.png" alt="alt text"></p><p>规则名字随便写，字段类型选<code>主机名</code>，字段值填你要重定向的域名。</p><p>URl 重定向类型选<code>动态</code>，表达式填写你的目标地址，例如：</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">concat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://www.ermao.net&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, http.request.uri.path)</span></span></code></pre></div><p>完事点击<code>保存</code></p><h2 id="_3-等待生效" tabindex="-1">3. 等待生效 <a class="header-anchor" href="#_3-等待生效" aria-label="Permalink to &quot;3. 等待生效&quot;">​</a></h2><p>这玩意生效还得几分钟到几小时，试着访问一下原域名，如果带着路径跳转到目标地址就说明生效了。</p><p>例如访问 <a href="https://blog.ermao.net/posts/vpn/" target="_blank" rel="noreferrer">https://blog.ermao.net/posts/vpn/</a> 就直接跳转到 <a href="https://www.ermao.net/posts/vpn/" target="_blank" rel="noreferrer">https://www.ermao.net/posts/vpn/</a> 了。</p><h2 id="_4-问题" tabindex="-1">4. 问题 <a class="header-anchor" href="#_4-问题" aria-label="Permalink to &quot;4. 问题&quot;">​</a></h2><p>有啥问题可以留言，我会尽量解答。</p>',21)])])}const u=a(l,[["render",s]]);export{m as __pageData,u as default};
